253		if (is_extension(format, "ppm"))
254			return fz_new_ppm_pixmap_writer_with_output(ctx, out, options);
255		if (is_extension(format, "pbm"))
256			return fz_new_pbm_pixmap_writer_with_output(ctx, out, options);
257		if (is_extension(format, "pkm"))
258			return fz_new_pkm_pixmap_writer_with_output(ctx, out, options);
