261	
262		if (is_extension(format, "pcl"))
263			return fz_new_pcl_writer_with_output(ctx, out, options);
264		if (is_extension(format, "pclm"))
265			return fz_new_pclm_writer_with_output(ctx, out, options);
266		if (is_extension(format, "ps"))
267			return fz_new_ps_writer_with_output(ctx, out, options);
268		if (is_extension(format, "pwg"))
269			return fz_new_pwg_writer_with_output(ctx, out, options);
270	
271		if (is_extension(format, "txt") || is_extension(format, "text"))
272			return fz_new_text_writer_with_output(ctx, "text", out, options);
273		if (is_extension(format, "html"))
274			return fz_new_text_writer_with_output(ctx, "html", out, options);
275		if (is_extension(format, "xhtml"))
276			return fz_new_text_writer_with_output(ctx, "xhtml", out, options);
277		if (is_extension(format, "stext") || is_extension(format, "stext.xml"))
278			return fz_new_text_writer_with_output(ctx, "stext.xml", out, options);
