334	{
335		if (!wri)
336			return NULL;
337		if (wri->dev)
338			fz_throw(ctx, FZ_ERROR_ARGUMENT, "called begin page without ending the previous page");
339		wri->dev = wri->begin_page(ctx, wri, mediabox);
340		return wri->dev;
341	}
