46	svg_begin_page(fz_context *ctx, fz_document_writer *wri_, fz_rect mediabox)
47	{
48		fz_svg_writer *wri = (fz_svg_writer*)wri_;
49		char path[PATH_MAX];
50	
51		float w = mediabox.x1 - mediabox.x0;
52		float h = mediabox.y1 - mediabox.y0;
53	
54		wri->count += 1;
55	
56		if (wri->path)
57		{
58			fz_format_output_path(ctx, path, sizeof path, wri->path, wri->count);
59			wri->out = fz_new_output_with_path(ctx, path, 0);
60		}
61		else
